"use client"

import React, { useEffect, useState, useRef } from 'react';
import { useRouter } from 'next/navigation';
import styles from './mypage.module.css';

// DTO 타입 정의
interface MemberDto {
  email: string;
  name: string;
  nickName: string;
  address: string;
  fileUrl?: string; 
}

export default function MyPage() {
  const router = useRouter();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [member, setMember] = useState<MemberDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [editMode, setEditMode] = useState(false);

  // 수정 입력값 (닉네임, 주소, 비밀번호)
  const [formData, setFormData] = useState({
    nickName: '',
    address: '',
    currentPassword: '', // 현재 비번 (검증용)
    newPassword: ''      // 새 비번 (변경용)
  });

  // 1. 내 정보 불러오기
 const fetchMember = async () => {
    const token = localStorage.getItem('token');
    
    // 토큰 자체가 없으면 로그인 페이지로 보내는 게 맞음
    if (!token) {
      alert("로그인이 필요합니다.");
      router.push('/authLogin');
      return;
    }

    try {
      const res = await fetch('http://localhost:8080/api/member/detail', {
        headers: { 'Authorization': `Bearer ${token}` }
      });

      if (res.ok) {
        // 성공 시 데이터 설정
        const data = await res.json();
        setMember(data);
        setFormData({ 
            nickName: data.nickName, 
            address: data.address || '',
            currentPassword: '',
            newPassword: ''
        });
      } else {
        // ⭐️ 에러 상태 코드별 처리 (여기가 핵심!)
        if (res.status === 401 || res.status === 403) {
            // 인증 실패(토큰 만료 등) -> 이때만 로그인 페이지로 이동
            alert("로그인 세션이 만료되었습니다. 다시 로그인해주세요.");
            localStorage.removeItem('token'); // 만료된 토큰 삭제
            router.push('/authLogin');
        } else if (res.status === 404) {
            // 주소 잘못됨 -> 로그인 문제는 아님
            alert("서버 연결 오류: 정보를 찾을 수 없습니다. (404)");
            router.push('/'); // 메인으로 이동하거나 그대로 유지
        } else {
            // 그 외 서버 에러(500 등)
            alert(`서버 오류가 발생했습니다. (코드: ${res.status})`);
            router.push('/'); // 메인으로 안전하게 이동
        }
      }
    } catch (e) {
      // 아예 서버가 꺼져있거나 네트워크 문제인 경우
      console.error(e);
      alert("서버와 통신할 수 없습니다. 잠시 후 다시 시도해주세요.");
      // 로그인 페이지로 튕기지 않음
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMember();
  }, []);

  // 2. 정보 수정 요청 (비밀번호 포함)
  const handleUpdate = async () => {
    const token = localStorage.getItem('token');

    // 새 비밀번호를 입력했는데 현재 비밀번호가 없다면 막기
    if (formData.newPassword && !formData.currentPassword) {
        alert("비밀번호를 변경하려면 현재 비밀번호를 입력해야 합니다.");
        return;
    }

    try {
      const res = await fetch('http://localhost:8080/api/member/update', {
        method: 'PUT',
        headers: { 
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(formData) // 닉네임, 주소, 비번들 전송
      });

      if (res.ok) {
        alert("성공적으로 수정되었습니다.");
        setEditMode(false);
        fetchMember(); // 최신 정보 갱신
      } else {
        // 백엔드에서 보낸 에러 메시지 (예: "현재 비밀번호가 일치하지 않습니다")
        const errorMsg = await res.text();
        alert("수정 실패: " + errorMsg);
      }
    } catch (e) {
      console.error(e);
      alert("서버 통신 오류");
    }
  };

  // 3. 이미지 파일 변경 (선택 즉시 업로드)
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;

    const file = e.target.files[0];
    const uploadData = new FormData();
    uploadData.append('file', file);

    const token = localStorage.getItem('token');

    try {
      const res = await fetch('http://localhost:8080/api/member/profileImg', {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}` },
        body: uploadData
      });

      if (res.ok) {
        alert("프로필 사진이 변경되었습니다.");
        fetchMember(); // 이미지 갱신
      } else {
        alert("이미지 업로드 실패");
      }
    } catch (e) {
      console.error(e);
    }
  };

  if (loading) return <div className={styles.loading}>로딩중...</div>;
  if (!member) return <div className={styles.loading}>회원 정보가 없습니다.</div>;

  return (
    <div className={styles.container}>
      <h2 className={styles.title}>마이페이지</h2>
      
      <div className={styles.card}>
        {/* === 프로필 이미지 섹션 === */}
        <div className={styles.profileSection}>
            <div 
                className={styles.imgWrapper} 
                onClick={() => fileInputRef.current?.click()}
            >
                <img 
                    src={member.fileUrl || "/img/default_profile.png"} 
                    alt="프로필" 
                    className={styles.profileImg}
                    onError={(e) => { e.currentTarget.src = "/img/default_profile.png"; }}
                />
                <div className={styles.overlay}>📷 변경</div>
            </div>
            <input 
                type="file" 
                ref={fileInputRef} 
                style={{display:'none'}} 
                accept="image/*"
                onChange={handleFileChange}
            />
        </div>

        {/* === 정보 입력 폼 === */}
        <div className={styles.infoSection}>
            
            {/* 이메일 (수정 불가) */}
            <div className={styles.row}>
                <label>이메일</label>
                <input type="text" value={member.email} disabled className={styles.inputDisabled} />
            </div>

            {/* 이름 (수정 불가) */}
            <div className={styles.row}>
                <label>이름</label>
                <input type="text" value={member.name} disabled className={styles.inputDisabled} />
            </div>

            {/* 닉네임 (수정 가능) */}
            <div className={styles.row}>
                <label>닉네임</label>
                {editMode ? (
                    <input 
                        value={formData.nickName} 
                        onChange={(e)=>setFormData({...formData, nickName: e.target.value})}
                        className={styles.input}
                    />
                ) : (
                    <div className={styles.textValue}>{member.nickName}</div>
                )}
            </div>

            {/* 주소 (수정 가능) */}
            <div className={styles.row}>
                <label>주소</label>
                {editMode ? (
                    <input 
                        value={formData.address} 
                        onChange={(e)=>setFormData({...formData, address: e.target.value})}
                        className={styles.input}
                    />
                ) : (
                    <div className={styles.textValue}>{member.address || "주소 없음"}</div>
                )}
            </div>

            {/* === 비밀번호 변경 섹션 (수정 모드일 때만 보임) === */}
            {editMode && (
                <div className={styles.passwordSection}>
                    <h4 className={styles.subTitle}>🔒 비밀번호 변경 (선택)</h4>
                    
                    <div className={styles.row}>
                        <label>현재 비밀번호</label>
                        <input 
                            type="password"
                            placeholder="변경하려면 현재 비밀번호 입력"
                            value={formData.currentPassword} 
                            onChange={(e)=>setFormData({...formData, currentPassword: e.target.value})}
                            className={styles.input}
                        />
                    </div>

                    <div className={styles.row}>
                        <label>새 비밀번호</label>
                        <input 
                            type="password"
                            placeholder="새 비밀번호 입력"
                            value={formData.newPassword} 
                            onChange={(e)=>setFormData({...formData, newPassword: e.target.value})}
                            className={styles.input}
                        />
                    </div>
                </div>
            )}

            {/* 버튼 그룹 */}
            <div className={styles.btnArea}>
                {editMode ? (
                    <>
                        <button onClick={handleUpdate} className={styles.saveBtn}>저장하기</button>
                        <button onClick={()=>{
                            setEditMode(false);
                            // 취소 시 입력값 원상복구
                            setFormData({
                                ...formData, 
                                nickName: member.nickName, 
                                address: member.address,
                                currentPassword: '',
                                newPassword: ''
                            });
                        }} className={styles.cancelBtn}>취소</button>
                    </>
                ) : (
                    <button onClick={()=>setEditMode(true)} className={styles.editBtn}>수정하기</button>
                )}
            </div>
        </div>
      </div>
    </div>
  );
}